#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
#define MAXM 100005
int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    return x[0] - y[0];
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int intervals[MAXN][2];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &intervals[i][0], &intervals[i][1]);
        }
        qsort(intervals, N, sizeof(intervals[0]), compare);
        for (int i = 0; i < M; i++) {
            int Pi;
            scanf("%d", &Pi);
            int waitingTime = -1;
            for (int j = 0; j < N; j++) {
                if (Pi >= intervals[j][0] && Pi < intervals[j][1]) {
                    waitingTime = 0;
                    break;
                } else if (Pi < intervals[j][0]) {
                    waitingTime = intervals[j][0] - Pi;
                    break;
                }
            }
            printf("%d\n", waitingTime);
        }
    }
    return 0;
}

